import subprocess
import os

def convertDocument(input_file, output_file, output_format):
    # Check if input file exists
    if not os.path.exists(input_file):
        raise FileNotFoundError(f"Input file '{input_file}' does not exist.")

    # Set LibreOffice path and command
    libreoffice_path = '/usr/bin/libreoffice'  # Change this to your LibreOffice installation path
    libreoffice_cmd = f"{libreoffice_path} --headless --convert-to {output_format} {input_file}"

    try:
        # Run the conversion command
        subprocess.run(libreoffice_cmd, shell=True, check=True)
        
        # Check if output file exists and is not empty
        if os.path.exists(output_file) and os.path.getsize(output_file) > 0:
            print(f"Conversion successful. Output file: {output_file}")
        else:
            raise Exception("Output file does not exist or is empty.")
    except subprocess.CalledProcessError as e:
        print(f"Error converting document: {e}")
    except Exception as e:
        print(f"An error occurred: {e}")

# Example usage
convertDocument('input.docx', 'output.pdf', 'pdf')